snapshot.eval/tests/unit/citation/citation-replic:
{
  "input": {
    "scenario": "mid-research-flynn",
    "user_message": "Apply the Evidence Explained replication test to the citation for src_004. Could another researcher find the same record with just this citation?"
  },
  "judge_context": [
    "Should confirm the citation passes the replication test: certificate number 4521 + jurisdiction (Pennsylvania Dept. of Health) + collection name + year (1908) is enough specificity for a researcher to retrieve the exact record",
    "Should identify the locator field: `citation_detail.where_within` should hold the certificate number (4521) — that's the within-collection identifier for vital records",
    "Should NOT recommend adding redundant detail (page numbers when the citation already has a certificate number) — over-specifying a citation that already replicates is busywork",
    "Should distinguish source-level classification (original) from information quality at the assertion level (some assertions on the death cert will be primary, others secondary depending on the informant) — these are independent classifications per research-schema-spec.md §7"
  ],
  "test": {
    "id": "ut_citation_002",
    "skill": "citation",
    "type": "positive"
  }
}

snapshot.eval/tests/unit/citation/negative-search:
{
  "input": {
    "scenario": "mid-research-flynn",
    "user_message": "Find another record I can use to corroborate the 1850 census source."
  },
  "judge_context": [
    "Should route to search-records rather than reformatting the existing src_001 citation"
  ],
  "negative": {
    "correct_skill": [
      "search-records"
    ],
    "explanation": "The user wants to search for more records, not refine the format of an existing citation. citation operates on entries already in research.json's `sources` array. Finding new records is search-records' job; once those records are extracted and a new source entry exists, then citation could be asked to format its citation."
  },
  "test": {
    "id": "ut_citation_003",
    "skill": "citation",
    "type": "negative"
  }
}

